const body = $input.first().json.body;
const data = body?.data;
if (!data || data.key?.fromMe) return [];
const text = (data.message?.conversation || data.message?.extendedTextMessage?.text || '').trim();
if (!text) return [];
const from = data.key?.remoteJid || '';
const parts = text.split(' ');
const cmd = parts[0].toLowerCase();
const args = parts.slice(1).join(' ').trim();
let actionType = 'direct';
let replyText = '';
let searchQuery = '';
let askQuery = '';
let apiPath = '';
let apiBody = null;
if (cmd === '/ajuda') {
  replyText = 'Ethra Nexus — Comandos:\n\n/buscar [termo]\n/pergunta [texto]\n/tarefas\n/ver [id]\n/aprovar [id]\n/rejeitar [id] [motivo]\n/wiki-pendentes\n/aprovar-wiki [id]\n/rejeitar-wiki [id] [motivo]\n/status';
} else if (cmd === '/status') {
  replyText = 'Status: online';
} else if (cmd === '/buscar') {
  if (!args) { replyText = 'Uso: /buscar [termo]'; }
  else { actionType = 'search'; searchQuery = args; }
} else if (cmd === '/pergunta') {
  if (!args) { replyText = 'Uso: /pergunta [texto]'; }
  else { actionType = 'ask'; askQuery = args; }
} else if (cmd === '/tarefas') {
  actionType = 'get'; apiPath = '/api/v1/tickets?status=pending_approval&limit=10';
} else if (cmd === '/ver') {
  if (!args) { replyText = 'Uso: /ver [id]'; }
  else { actionType = 'get'; apiPath = '/api/v1/tickets/' + args; }
} else if (cmd === '/aprovar') {
  if (!args) { replyText = 'Uso: /aprovar [id]'; }
  else { actionType = 'post'; apiPath = '/api/v1/tickets/' + args + '/approve'; apiBody = {}; }
} else if (cmd === '/rejeitar') {
  const argParts = args.split(' ');
  const ticketId = argParts[0];
  const reason = argParts.slice(1).join(' ');
  if (!ticketId) { replyText = 'Uso: /rejeitar [id] [motivo]'; }
  else { actionType = 'post'; apiPath = '/api/v1/tickets/' + ticketId + '/reject'; apiBody = { rejection_reason: reason || 'Rejeitado' }; }
} else if (cmd === '/wiki-pendentes') {
  actionType = 'get'; apiPath = '/api/v1/wiki/agent-writes/pending';
} else if (cmd === '/aprovar-wiki') {
  if (!args) { replyText = 'Uso: /aprovar-wiki [id]'; }
  else { actionType = 'post'; apiPath = '/api/v1/wiki/agent-writes/' + args + '/approve'; apiBody = {}; }
} else if (cmd === '/rejeitar-wiki') {
  const argParts = args.split(' ');
  const writeId = argParts[0];
  const reason = argParts.slice(1).join(' ');
  if (!writeId) { replyText = 'Uso: /rejeitar-wiki [id] [motivo]'; }
  else { actionType = 'post'; apiPath = '/api/v1/wiki/agent-writes/' + writeId + '/reject'; apiBody = { reason: reason || '' }; }
} else {
  replyText = 'Comando nao reconhecido. Use /ajuda.';
}
return [{ json: { from, actionType, replyText, searchQuery, askQuery, apiPath, apiBody } }];

const results = $input.first().json.data || [];
const from = $('Parse Comando').item.json.from;
const query = $('Parse Comando').item.json.searchQuery;
if (results.length === 0) {
  return [{ json: { from, replyText: 'Nenhum resultado para: ' + query } }];
}
const lines = results.map((r, i) => (i+1) + '. ' + r.title + ' (' + r.type + ')');
return [{ json: { from, replyText: 'Resultados para "' + query + '":\n\n' + lines.join('\n') } }];

const token = $input.first().json.token;
const parsed = $('Parse Comando').item.json;
const baseUrl = process.env.NEXUS_API_URL || 'https://api.nexus.ethra.com.br';
const response = await fetch(baseUrl + parsed.apiPath, {
  headers: { 'Authorization': 'Bearer ' + token }
});
const result = await response.json();
const from = parsed.from;
const apiPath = parsed.apiPath;
let replyText;
if (!response.ok) {
  replyText = 'Erro ' + response.status + ': ' + (result.error || 'Falha');
} else if (apiPath.includes('tickets?')) {
  const list = result.data || [];
  if (list.length === 0) {
    replyText = 'Nenhuma tarefa pendente.';
  } else {
    const lines = list.slice(0, 8).map((t, i) => (i+1) + '. ' + t.title + '\n   ID: ' + t.id.slice(0,8) + '...');
    replyText = '*Tarefas pendentes:*\n\n' + lines.join('\n\n') + '\n\nUse /ver [id]';
  }
} else if (apiPath.includes('/tickets/') && !apiPath.includes('?')) {
  const t = result.data || result;
  if (!t || !t.id) {
    replyText = 'Tarefa nao encontrada.';
  } else {
    replyText = '*' + t.title + '*\nStatus: ' + t.status + '\nID: ' + t.id;
    if (t.description) replyText += '\nDesc: ' + t.description;
  }
} else if (apiPath.includes('agent-writes')) {
  const list = result.data || [];
  if (list.length === 0) {
    replyText = 'Nenhum conhecimento pendente.';
  } else {
    const lines = list.slice(0, 8).map((w, i) => (i+1) + '. ' + w.title + ' (' + w.type + ')\n   ID: ' + w.id.slice(0,8) + '...');
    replyText = '*Conhecimentos pendentes:*\n\n' + lines.join('\n\n');
  }
} else {
  replyText = JSON.stringify(result).slice(0, 400);
}
return [{ json: { from, replyText } }];

const token = $input.first().json.token;
const parsed = $('Parse Comando').item.json;
const baseUrl = process.env.NEXUS_API_URL || 'https://api.nexus.ethra.com.br';
const response = await fetch(baseUrl + parsed.apiPath, {
  method: 'POST',
  headers: {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(parsed.apiBody || {})
});
const result = await response.json();
const from = parsed.from;
const apiPath = parsed.apiPath;
let replyText;
if (!response.ok) {
  replyText = 'Erro ' + response.status + ': ' + (result.error || 'Falha');
} else if (apiPath.includes('/approve')) {
  replyText = 'Aprovado com sucesso!';
} else if (apiPath.includes('/reject')) {
  replyText = 'Rejeitado.';
} else {
  replyText = 'Acao realizada.';
}
return [{ json: { from, replyText } }];
